package commands

type Topic struct {
	topicId            string
	title              string
	description        string
	prerequisites      string
	knowledge          string
	flow               string
	quiz               string
	completionCriteria string
}

type Section struct {
	sectionId   string
	title       string
	description string
	topics      []Topic
}

type Author struct {
	authorId string
	name     string
}

type Category struct {
	categoryId string
	name       string
}

type Course struct {
	courseId      string
	title         string
	description   string
	slug          string
	tags          []string
	publishStatus string
	category      Category
	publishedAt   *string
	author        Author
	visibility    string
	sections      []Section
}

type EnrollNumber struct {
	SectionNumber *int
	TopicNumber *int
}



var ErrEnrollmentNumberIsNotFound = errors.New("enrollment number is not found");

func (course *Course)enroll(enrollNumber EnrollNumber, progress){
	sectionNumber := 1
	topicNumber := 1

	if enrollNumber.SectionNumber != nil {
		sectionNumber = *enrollNumber.SectionNumber;

		if enrollNumber.TopicNumber == nil {
			topicNumber = 1;
		} else {
			topicNumber = *enrollNumber.TopicNumber;
		}

	} else if enrollNumber.SectionNumber == nil && enrollNumber.TopicNumber == nil {
		status, lastSectionNumber, lastTopicNumber = progress.lastTopic();
		if status== "completed" {
			sectionNumber, topicNumber = course.nextTopic(lastSectionNumber, lastTopicNumber)
		} else if status == "started" {
			sectionNumber = lastSectionNumber
			topicNumber =  lastTopicNumber
		} else {
			sectionNumber = 1
			topicNumber = 1
		}
	}
	section, topic, err := course.getTopic(sectionNumber, topicNumber)
	if err != nil {
		return ErrEnrollmentNumberIsNotFound;
	}

	_ = progress.start(section, topic)

	return progress;
}

