    16→}
    17→
    18→type UUID struct {
    19→	Bytes [16]byte
    20→	Valid bool
    21→}
    22→
    23→// ScanUUID implements the [UUIDScanner] interface.
    24→func (b *UUID) ScanUUID(v UUID) error {
    25→	*b = v
    26→	return nil
    27→}
    28→
    29→// UUIDValue implements the [UUIDValuer] interface.
    30→func (b UUID) UUIDValue() (UUID, error) {
    31→	return b, nil
    32→}
    33→
    34→// parseUUID converts a string UUID in standard form to a byte array.
    35→func parseUUID(src string) (dst [16]byte, err error) {
    36→	switch len(src) {
    37→	case 36:
    38→		src = src[0:8] + src[9:13] + src[14:18] + src[19:23] + src[24:]
    39→	case 32:
    40→		// dashes already stripped, assume valid
    41→	default:
    42→		// assume invalid.
    43→		return dst, fmt.Errorf("cannot parse UUID %v", src)
    44→	}
    45→
    46→	buf, err := hex.DecodeString(src)
    47→	if err != nil {
    48→		return dst, err
    49→	}
    50→
    51→	copy(dst[:], buf)
    52→	return dst, err
    53→}
    54→
    55→// encodeUUID converts a uuid byte array to UUID standard string form.
    56→func encodeUUID(src [16]byte) string {
    57→	var buf [36]byte
    58→
    59→	hex.Encode(buf[0:8], src[:4])
    60→	buf[8] = '-'
    61→	hex.Encode(buf[9:13], src[4:6])
    62→	buf[13] = '-'
    63→	hex.Encode(buf[14:18], src[6:8])
    64→	buf[18] = '-'
    65→	hex.Encode(buf[19:23], src[8:10])
    66→	buf[23] = '-'
    67→	hex.Encode(buf[24:], src[10:])
    68→
    69→	return string(buf[:])
    70→}
    71→
    72→// Scan implements the [database/sql.Scanner] interface.
    73→func (dst *UUID) Scan(src any) error {
    74→	if src == nil {
    75→		*dst = UUID{}
    76→		return nil
    77→	}
    78→
    79→	switch src := src.(type) {
    80→	case string:
    81→		buf, err := parseUUID(src)
    82→		if err != nil {
    83→			return err
    84→		}
    85→		*dst = UUID{Bytes: buf, Valid: true}
    86→		return nil
    87→	}
    88→
    89→	return fmt.Errorf("cannot scan %T", src)
    90→}
    91→
    92→// Value implements the [database/sql/driver.Valuer] interface.
    93→func (src UUID) Value() (driver.Value, error) {
    94→	if !src.Valid {
    95→		return nil, nil
    96→	}
    97→
    98→	return encodeUUID(src.Bytes), nil
    99→}
