   101→func (src UUID) String() string {
   102→	if !src.Valid {
   103→		return ""
   104→	}
   105→
   106→	return encodeUUID(src.Bytes)
   107→}
   108→
   109→// MarshalJSON implements the [encoding/json.Marshaler] interface.
   110→func (src UUID) MarshalJSON() ([]byte, error) {
   111→	if !src.Valid {
   112→		return []byte("null"), nil
   113→	}
   114→
   115→	var buff bytes.Buffer
   116→	buff.WriteByte('"')
   117→	buff.WriteString(encodeUUID(src.Bytes))
   118→	buff.WriteByte('"')
   119→	return buff.Bytes(), nil
   120→}
   121→
   122→// UnmarshalJSON implements the [encoding/json.Unmarshaler] interface.
   123→func (dst *UUID) UnmarshalJSON(src []byte) error {
   124→	if bytes.Equal(src, []byte("null")) {
   125→		*dst = UUID{}
   126→		return nil
   127→	}
   128→	if len(src) != 38 {
   129→		return fmt.Errorf("invalid length for UUID: %v", len(src))
   130→	}
   131→	buf, err := parseUUID(string(src[1 : len(src)-1]))
   132→	if err != nil {
   133→		return err
   134→	}
   135→	*dst = UUID{Bytes: buf, Valid: true}
   136→	return nil
   137→}
