   149→func (UUIDCodec) PlanEncode(m *Map, oid uint32, format int16, value any) EncodePlan {
   150→	if _, ok := value.(UUIDValuer); !ok {
   151→		return nil
   152→	}
   153→
   154→	switch format {
   155→	case BinaryFormatCode:
   156→		return encodePlanUUIDCodecBinaryUUIDValuer{}
   157→	case TextFormatCode:
   158→		return encodePlanUUIDCodecTextUUIDValuer{}
   159→	}
   160→
