   164→type encodePlanUUIDCodecBinaryUUIDValuer struct{}
   165→
   166→func (encodePlanUUIDCodecBinaryUUIDValuer) Encode(value any, buf []byte) (newBuf []byte, err error) {
   167→	uuid, err := value.(UUIDValuer).UUIDValue()
   168→	if err != nil {
   169→		return nil, err
   170→	}
   171→
   172→	if !uuid.Valid {
   173→		return nil, nil
   174→	}
   175→
   176→	return append(buf, uuid.Bytes[:]...), nil
   177→}
   178→
   179→type encodePlanUUIDCodecTextUUIDValuer struct{}
