   181→func (encodePlanUUIDCodecTextUUIDValuer) Encode(value any, buf []byte) (newBuf []byte, err error) {
   182→	uuid, err := value.(UUIDValuer).UUIDValue()
   183→	if err != nil {
   184→		return nil, err
   185→	}
   186→
   187→	if !uuid.Valid {
   188→		return nil, nil
   189→	}
   190→
   191→	return append(buf, encodeUUID(uuid.Bytes)...), nil
