   194→func (UUIDCodec) PlanScan(m *Map, oid uint32, format int16, target any) ScanPlan {
   195→	switch format {
   196→	case BinaryFormatCode:
   197→		switch target.(type) {
   198→		case UUIDScanner:
   199→			return scanPlanBinaryUUIDToUUIDScanner{}
   200→		case TextScanner:
   201→			return scanPlanBinaryUUIDToTextScanner{}
   202→		}
   203→	case TextFormatCode:
   204→		switch target.(type) {
